void TCS3200_GPIO_Init(void)
{
    /* 使能 GPIO 时钟 */
    __HAL_RCC_GPIOA_CLK_ENABLE();

    /* 配置 TCS3200 的 S0、S1 引脚为推挽输出 */
    GPIO_InitStruct.Pin = TCS3200_S0_PIN | TCS3200_S1_PIN;
    GPIO_InitStruct.Mode = GPIO_MODE_OUTPUT_PP;
    GPIO_InitStruct.Speed = GPIO_SPEED_FREQ_HIGH;
    HAL_GPIO_Init(TCS3200_GPIO_PORT, &GPIO_InitStruct);

    /* 配置 TCS3200 的 OUT 引脚为上拉输入 */
    GPIO_InitStruct.Pin = TCS3200_OUT_PIN;
    GPIO_InitStruct.Mode = GPIO_MODE_INPUT;
    GPIO_InitStruct.Pull = GPIO_PULLUP;
    HAL_GPIO_Init(TCS3200_GPIO_PORT, &GPIO_InitStruct);
}

/* TCS3200 定时器初始化函数 */
void TCS3200_Timer_Init(void)
{
    /* 定时器时钟使能 */
    __HAL_RCC_TIM2_CLK_ENABLE();

    /* 定时器 2 管脚配置，输出 PWM */
    GPIO_InitStruct.Pin = TCS3200_G_PIN;
    GPIO_InitStruct.Mode = GPIO_MODE_AF_PP;
    GPIO_InitStruct.Speed = GPIO_SPEED_FREQ_LOW;
    HAL_GPIO_Init(TCS3200_GPIO_PORT, &GPIO_InitStruct);

    /* 定时器 2 配置 */
    htim2.Instance = TIM2;
    htim2.Init.Prescaler = 0;
    htim2.Init.CounterMode = TIM_COUNTERMODE_UP;
    htim2.Init.Period = TCS3200_TIMER_COUNTS - 1;
    htim2.Init.ClockDivision = TIM_CLOCKDIVISION_DIV1;
